import { Pool } from "../../shared/db/connection";
import { INotificationRepository, CreateNotificationDTO } from "./notification.repository.interface";
import { Notification } from "../../shared/types/index";

export class NotificationRepository implements INotificationRepository {
  constructor(private readonly pool: Pool) {}

  async create(notification: CreateNotificationDTO): Promise<Notification> {
    const query = `
      INSERT INTO notifications (employee_id, leave_request_id, type, message)
      VALUES ($1, $2, $3, $4)
      RETURNING *;
    `;
    const values = [notification.employeeId, notification.leaveRequestId || null, notification.type, notification.message];
    const result = await this.pool.query(query, values);
    return this.mapRowToNotification(result.rows[0]);
  }

  async findById(id: string): Promise<Notification | null> {
    const query = `SELECT * FROM notifications WHERE id = $1`;
    const result = await this.pool.query(query, [id]);
    return result.rows[0] ? this.mapRowToNotification(result.rows[0]) : null;
  }

  async findByEmployeeId(employeeId: string): Promise<Notification[]> {
    const query = `SELECT * FROM notifications WHERE employee_id = $1 ORDER BY created_at DESC`;
    const result = await this.pool.query(query, [employeeId]);
    return result.rows.map(this.mapRowToNotification);
  }

  async updateReadStatus(id: string, readStatus: ReadStatus): Promise<void> {
    const query = `UPDATE notifications SET read_status = $1 WHERE id = $2`;
    await this.pool.query(query, [readStatus, id]);
  }

  async updateSentStatus(id: string, sentStatus: SentStatus, sentAt?: Date): Promise<void> {
    const query = `UPDATE notifications SET sent_status = $1, sent_at = $2 WHERE id = $3`;
    await this.pool.query(query, [sentStatus, sentAt || null, id]);
  }

  private mapRowToNotification(row: any): Notification {
    return {
      id: row.id,
      employeeId: row.employee_id,
      leaveRequestId: row.leave_request_id,
      type: row.type,
      message: row.message,
      readStatus: row.read_status,
      sentStatus: row.sent_status,
      createdAt: row.created_at,
      sentAt: row.sent_at,
    };
  }
}","File: src/modules/audit/audit.repository.ts
import { Pool } from "../../shared/db/connection";
import { IAuditRepository, CreateAuditEntryDTO } from "./audit.repository.interface";
import { AuditRecord } from "../../shared/types/index";

export class AuditRepository implements IAuditRepository {
  constructor(private readonly pool: Pool) {}

  async create(entry: CreateAuditEntryDTO): Promise<AuditRecord> {
    const query = `
      INSERT INTO audit_log (entity_type, entity_id, action, changed_by, old_values, new_values)
      VALUES ($1, $2, $3, $4, $5, $6)
      RETURNING *;
    `;
    const values = [entry.entityType, entry.entityId, entry.action, entry.changedBy, entry.oldValues || null, entry.newValues || null];
    const result = await this.pool.query(query, values);
    return this.mapRowToAuditRecord(result.rows[0]);
  }

  async findByEntity(entityType: string, entityId: string): Promise<AuditRecord[]> {
    const query = `SELECT * FROM audit_log WHERE entity_type = $1 AND entity_id = $2 ORDER BY changed_at DESC`;
    const result = await this.pool.query(query, [entityType, entityId]);
    return result.rows.map(this.mapRowToAuditRecord);
  }

  private mapRowToAuditRecord(row: any): AuditRecord {
    return {
      id: row.id,
      entityType: row.entity_type,
      entityId: row.entity_id,
      action: row.action,
      changedBy: row.changed_by,
      changedAt: row.changed_at,
      oldValues: row.old_values,
      newValues: row.new_values,
    };
  }
}","File: src/modules/notification/notification.service.ts
import { INotificationService } from "./notification.service.interface";
import { INotificationRepository } from "./notification.repository.interface";
import { Notification, NotificationType } from "../../shared/types/index";

export class NotificationService implements INotificationService {
  constructor(private readonly notificationRepository: INotificationRepository) {}

  async createNotification(employeeId: string, leaveRequestId: string | undefined, type: NotificationType, message: string): Promise<Notification> {
    return this.notificationRepository.create({ employeeId, leaveRequestId, type, message });
  }

  async getNotification(id: string): Promise<Notification | null> {
    return this.notificationRepository.findById(id);
  }

  async getEmployeeNotifications(employeeId: string): Promise<Notification[]> {
    return this.notificationRepository.findByEmployeeId(employeeId);
  }

  async markAsRead(id: string): Promise<void> {
    await this.notificationRepository.updateReadStatus(id, 'read');
  }

  async markAsSent(id: string, sentAt?: Date): Promise<void> {
    await this.notificationRepository.updateSentStatus(id, 'sent', sentAt);
  }
}","File: src/modules/audit/audit.service.ts
